form:Form.form:Scripts:
		function nombreyapellido ()
	{
		Ctrl('d_familiar_pos').SetCValue(Ctrl('d_apellido').GetCValue()+', '+Ctrl('d_nombres').GetCValue());		
	}

function valida (myThis)
	{    
		if (Ctrl('f_nacimiento').GetXValue() != "")
		{
			if (Ctrl('f_fallecimiento').GetXValue() != "")
			{
				if (Ctrl('f_nacimiento').GetXValue() > Ctrl('f_fallecimiento').GetXValue())
				{
				  myThis.SetError('La fecha de nacimiento debe ser anterior a la fecha de fallecimiento');
					return false;
				}		
			} 		
		}		
		else		
		{
		if (Ctrl('f_fallecimiento').GetXValue() != "")
			{
				myThis.SetError('La fecha de nacimiento debe ser anterior a la fecha de fallecimiento');
				return false;
		  }		
		}  	


		if (Ctrl('e_anio_inic_esc').GetXValue() != "")
		{
			if (Ctrl('e_anio_fin_esc').GetXValue() != "")
			{
				if (Ctrl('e_anio_inic_esc').GetXValue() > Ctrl('e_anio_fin_esc').GetXValue())
				{
				  myThis.SetError('La fecha de inicio de escolaridad debe ser anterior a la fecha de fin');
					return false;
				}		
			} 		
		}		
		else		
		{
		if (Ctrl('e_anio_fin_esc').GetXValue() != "")
			{
				myThis.SetError('La fecha de inicio de escolaridad debe ser anterior a la fecha de fin');
				return false;
		  }		
		} 


		if (Ctrl('f_desde_IG').GetXValue() != "")
		{
			if (Ctrl('f_hasta_IG').GetXValue() != "")
			{
				if (Ctrl('f_desde_IG').GetXValue() > Ctrl('f_hasta_IG').GetXValue())
				{
				  myThis.SetError('La fecha de inicio de impustos a las ganancias debe seranterior a la fecha de fin');
					return false;
				}		
			} 		
		}		
		else		
		{
		if (Ctrl('f_hasta_IG').GetXValue() != "")
			{
				myThis.SetError('La fecha de inicio de impuestos a las ganacionas debe seranterior a la fecha de fin');
				return false;
		  }		
		}    					     

	return true;
	}
